#include <stdio.h>
#include <sys/mman.h>
#include <sys/wait.h>
#include <unistd.h>
#include <string.h>

int main(void) {
    size_t ps = (size_t)getpagesize();
    char *shared = (char *)mmap(NULL, ps,
        PROT_READ | PROT_WRITE,
        MAP_PRIVATE | MAP_ANONYMOUS, -1, 0);
    if (shared == MAP_FAILED) { perror("mmap"); return 1; }
    strcpy(shared, "before fork");
    printf("Parent before fork: %s\n", shared);
    fflush(stdout);
    pid_t pid = ____();
    if (pid < 0) { perror("fork"); return 1; }
    if (pid == 0) {
        /* enfant */
        printf("Child sees: %s\n", shared);
        strcpy(shared, "child wrote");
        printf("Child after write: %s\n", shared);
        fflush(stdout);
        _exit(0);
    }
    /* parent */
    int status;
    ____(pid, &status, 0);
    printf("Parent after child: %s\n", shared);
    printf("COW isolated: %s\n",
        strcmp(shared, "before fork") == 0 ? "yes" : "no");
    munmap(shared, ps);
    return 0;
}

