void example_shared_fork(void) {
    size_t ps = (size_t)getpagesize();
    char *s = mmap(NULL, ps, PROT_READ|PROT_WRITE, MAP_SHARED|MAP_ANONYMOUS, -1, 0);
    strcpy(s, "shared");
    pid_t p = fork();
    if (p == 0) { strcpy(s, "child"); fflush(stdout);
        _exit(0); }
    waitpid(p, NULL, 0);
    printf("MAP_SHARED: parent voit '%s' (modifié par enfant)\n", s);
    munmap(s, ps);
}

